div.script:
function andykaInitMap() {
    var mapEl = document.getElementById('andyka_gmap');
    if (!mapEl) return;

    var DEFAULT_LAT = -8.6705, DEFAULT_LNG = 115.2126;
    var initLat = parseFloat(mapEl.dataset.lat) || 0;
    var initLng = parseFloat(mapEl.dataset.lng) || 0;
    var gmapsLink = mapEl.dataset.gmapsLink || '';

    if ((initLat === 0 || initLng === 0) && gmapsLink) {
        var m = gmapsLink.match(/@(-?\d+\.?\d*),(-?\d+\.?\d*)/);
        if (!m) m = gmapsLink.match(/[?&]q=(-?\d+\.?\d*),(-?\d+\.?\d*)/);
        if (m) { initLat = parseFloat(m[1]); initLng = parseFloat(m[2]); }
    }
    if (initLat === 0 && initLng === 0) { initLat = DEFAULT_LAT; initLng = DEFAULT_LNG; }

    var center = { lat: initLat, lng: initLng };
    var map = new google.maps.Map(mapEl, {
        center: center, zoom: 15,
        mapTypeControl: false, streetViewControl: false
    });
    var marker = new google.maps.Marker({
        position: center, map: map, draggable: true,
        title: 'Seret untuk memilih lokasi'
    });
    var geocoder = new google.maps.Geocoder();

    if (initLat !== DEFAULT_LAT || initLng !== DEFAULT_LNG) {
        updateCoords(initLat, initLng);
    }

    map.addListener('click', function (e) {
        marker.setPosition(e.latLng);
        handlePosition(e.latLng.lat(), e.latLng.lng());
    });
    marker.addListener('dragend', function (e) {
        handlePosition(e.latLng.lat(), e.latLng.lng());
    });

    var btn = document.getElementById('andyka_btn_my_location');
    if (btn) {
        btn.addEventListener('click', function () {
            if (!navigator.geolocation) { alert('Browser tidak mendukung geolokasi.'); return; }
            btn.disabled = true;
            btn.innerHTML = '<i class="fa fa-spinner fa-spin me-1"></i>Mendeteksi...';
            navigator.geolocation.getCurrentPosition(
                function (pos) {
                    var lat = pos.coords.latitude, lng = pos.coords.longitude;
                    var ll = new google.maps.LatLng(lat, lng);
                    map.setCenter(ll); map.setZoom(17); marker.setPosition(ll);
                    handlePosition(lat, lng);
                    btn.disabled = false;
                    btn.innerHTML = '<i class="fa fa-crosshairs me-1"></i>Lokasi Saya';
                },
                function (err) {
                    var msg = 'Tidak dapat mendeteksi lokasi.';
                    if (err.code === 1) msg = 'Akses lokasi ditolak oleh browser.';
                    alert(msg); btn.disabled = false;
                    btn.innerHTML = '<i class="fa fa-crosshairs me-1"></i>Lokasi Saya';
                },
                { enableHighAccuracy: true, timeout: 10000 }
            );
        });
    }

    var gmapsInput = document.getElementById('gmaps_link');
    if (gmapsInput) {
        gmapsInput.addEventListener('change', function () {
            var m2 = gmapsInput.value.match(/@(-?\d+\.?\d*),(-?\d+\.?\d*)/);
            if (!m2) m2 = gmapsInput.value.match(/[?&]q=(-?\d+\.?\d*),(-?\d+\.?\d*)/);
            if (m2) {
                var lt = parseFloat(m2[1]), ln = parseFloat(m2[2]);
                var ll = new google.maps.LatLng(lt, ln);
                map.setCenter(ll); map.setZoom(15); marker.setPosition(ll);
                handlePosition(lt, ln);
            }
        });
    }

    function handlePosition(lat, lng) {
        updateCoords(lat, lng);
        updateInputs(lat, lng);
        reverseGeocode(lat, lng);
    }

    function reverseGeocode(lat, lng) {
        geocoder.geocode({ location: { lat: lat, lng: lng } }, function (results, status) {
            if (status === 'OK' && results[0]) {
                var r = results[0];
                var addrEl = document.getElementById('andyka_map_address');
                if (addrEl) addrEl.textContent = r.formatted_address;
                fillAddressFields(r.address_components);
            }
        });
    }

    function fillAddressFields(components) {
        var get = function(type) {
            for (var i = 0; i < components.length; i++) {
                if (components[i].types.indexOf(type) !== -1) return components[i].long_name;
            }
            return '';
        };
        var streetNum = get('street_number');
        var route = get('route');
        var street = [route, streetNum].filter(Boolean).join(' ');
        var sublocality = get('sublocality_level_1') || get('sublocality') || '';
        var city = get('locality') || get('administrative_area_level_2') || '';
        var zip = get('postal_code') || '';
        var stateName = get('administrative_area_level_1') || '';
        var countryName = get('country') || '';

        setField('street', street || sublocality);
        setField('street2', sublocality && street ? sublocality : '');
        setField('city', city);
        setField('zip', zip);
        setField('zipcode', zip);
        setSelectByText('state_id', stateName);
        setSelectByText('country_id', countryName);
    }

    function setField(name, value) {
        var el = document.querySelector('input[name="' + name + '"], textarea[name="' + name + '"]');
        if (el && value) { el.value = value; el.dispatchEvent(new Event('change', {bubbles: true})); }
    }

    function setSelectByText(name, text) {
        if (!text) return;
        var sel = document.querySelector('select[name="' + name + '"]');
        if (!sel) return;
        for (var i = 0; i < sel.options.length; i++) {
            if (sel.options[i].text.toLowerCase().indexOf(text.toLowerCase()) !== -1) {
                sel.value = sel.options[i].value;
                sel.dispatchEvent(new Event('change', {bubbles: true}));
                break;
            }
        }
    }

    function updateCoords(lat, lng) {
        var el = document.getElementById('andyka_map_info');
        var co = document.getElementById('andyka_map_coords');
        if (el) el.style.display = 'block';
        if (co) co.textContent = lat.toFixed(6) + ', ' + lng.toFixed(6);
    }

    function updateInputs(lat, lng) {
        var a = document.getElementById('andyka_input_lat');
        var b = document.getElementById('andyka_input_lng');
        if (a) a.value = lat; if (b) b.value = lng;
    }
}

